import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class ControlsExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        // 1. Label
        Label label = new Label("This is a Label");
        label.setStyle("-fx-font-size: 16px; -fx-font-weight: bold;");
        root.getChildren().add(label);

        // 2. Button
        Button button = new Button("Click Me!");
        button.setStyle("-fx-background-color: #4CAF50; -fx-text-fill: white; -fx-font-size: 14px;");
        root.getChildren().add(button);

        // 3. TextField
        TextField textField = new TextField();
        textField.setPromptText("Enter your name...");
        textField.setMaxWidth(200);
        root.getChildren().add(textField);

        // 4. TextArea
        TextArea textArea = new TextArea();
        textArea.setPromptText("Enter a description...");
        textArea.setMaxWidth(300);
        textArea.setPrefHeight(100);
        root.getChildren().add(textArea);

        // 5. CheckBox
        CheckBox checkBox = new CheckBox("I agree to the terms");
        checkBox.setSelected(true);
        root.getChildren().add(checkBox);

        // 6. RadioButton (with ToggleGroup)
        ToggleGroup radioGroup = new ToggleGroup();
        RadioButton radio1 = new RadioButton("Option A");
        RadioButton radio2 = new RadioButton("Option B");
        RadioButton radio3 = new RadioButton("Option C");
        radio1.setToggleGroup(radioGroup);
        radio2.setToggleGroup(radioGroup);
        radio3.setToggleGroup(radioGroup);
        radio1.setSelected(true);

        VBox radioBox = new VBox(5);
        radioBox.setAlignment(Pos.CENTER);
        radioBox.getChildren().addAll(radio1, radio2, radio3);
        root.getChildren().add(radioBox);

        // 7. ComboBox
        ComboBox<String> comboBox = new ComboBox<>();
        comboBox.getItems().addAll("Option 1", "Option 2", "Option 3", "Option 4");
        comboBox.setValue("Select an option...");
        comboBox.setMaxWidth(200);
        root.getChildren().add(comboBox);

        // 8. ListView
        ListView<String> listView = new ListView<>();
        listView.getItems().addAll("Item 1", "Item 2", "Item 3", "Item 4", "Item 5");
        listView.setMaxWidth(200);
        listView.setPrefHeight(100);
        root.getChildren().add(listView);

        // 9. Separator
        Separator separator = new Separator();
        separator.setMaxWidth(300);
        root.getChildren().add(separator);

        // 10. Slider
        Slider slider = new Slider(0, 100, 50);
        slider.setShowTickLabels(true);
        slider.setShowTickMarks(true);
        slider.setMajorTickUnit(20);
        slider.setMaxWidth(300);
        root.getChildren().add(slider);

        // 11. ProgressBar
        ProgressBar progressBar = new ProgressBar(0.5);
        progressBar.setMaxWidth(300);
        root.getChildren().add(progressBar);

        // 12. Tooltip
        Button tooltipBtn = new Button("Hover me!");
        Tooltip tooltip = new Tooltip("This is a tooltip message");
        tooltipBtn.setTooltip(tooltip);
        root.getChildren().add(tooltipBtn);

        // 13. Label with hyperlink style
        Hyperlink hyperlink = new Hyperlink("Click here for help");
        root.getChildren().add(hyperlink);

        Scene scene = new Scene(root, 500, 700);

        primaryStage.setTitle("JavaFX Basic Controls");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

